def lambda_handler(event, context):
    # Get the IAM role for this Lambda function
    iam = boto3.client('iam')
    
    try:
        response = iam.get_role(RoleName=context.invoked_function_name)
        
        if 'Role' in response:
            print(f"Using IAM role: {response['Role']['Arn']}")
            
            # Use the shared IAM role definition here
            # iam_role = {
            #     "Version": "2012-10-17",
            #     "Statement": [
            #         ...
            #     ]
            # }
            
            # Assume the IAM role for this Lambda function
            sts_client = boto3.client('sts')
            assumed_role_object = sts_client.assume_role(
                RoleArn=response['Role']['Arn'],
                RoleSessionName=context.invoked_function_name
            )
            
            # Get the temporary security credentials from the assumed role
            temp_creds = assumed_role_object['Credentials']
            
            # Use these credentials to interact with AWS services
            s3 = boto3.client('s3', aws_access_key_id=temp_creds['AccessKeyId'],
                              aws_secret_access_key=temp_creds['SecretAccessKey'],
                              aws_session_token=temp_creds['SessionToken'])
            
            # Example usage: list the objects in an S3 bucket
            response = s3.list_objects_v2(Bucket='my-bucket')
            print(response)
            
    except ClientError as e:
        if e.response['Error']['Code'] == 'AccessDenied':
            print(f"Access denied for IAM role: {response['Role']['Arn']}")
        else:
            raise